#include<bits/stdc++.h>
using namespace std;
int main(void){
    int n,m,a[1005][1005],p,x,y;
    cin>>n>>m;
    for(int i=1;i<=n;i++){
    	for(int j=1;j<=n;j++){
    		scanf("%d",&a[i][j]);
		}
	}
	while(m--){
		scanf("%d%d%d",&p,&x,&y);
		if(p==1){
			swap(a[x],a[y]);
		}else{
			for(int i=1;i<=n;i++)swap(a[i][x],a[i][y]);
		}
	}
	for(int i=1;i<=n;i++){
    	for(int j=1;j<=n;j++){
    		printf("%d ",a[i][j]);
		}
		printf("\n");
	}
    return false;
}
